import axios from 'axios';

export class MarketService {
  private static readonly BASE_URL = 'https://api.twelvedata.com';
  private static readonly RAPID_API_BASE_URL = 'https://live-stock-market.p.rapidapi.com';
  private static readonly API_KEY = process.env.TWELVE_DATA_API_KEY;
  private static readonly RAPIDAPI_KEY = process.env.RAPIDAPI_KEY;
  private static readonly PRICE_TTL_MS = 5000;
  private static readonly CANDLE_TTL_MS = 60000;
  private static readonly priceCache = new Map<string, { value: any; expiresAt: number }>();
  private static readonly candleCache = new Map<string, { value: any; expiresAt: number }>();

  private static readonly SYMBOL_MAP: Record<string, string> = {
    EURUSD: 'EUR/USD',
    GBPUSD: 'GBP/USD',
    USDJPY: 'USD/JPY',
    AUDUSD: 'AUD/USD',
    USDCAD: 'USD/CAD',
    XAUUSD: 'XAU/USD',
    BTCUSD: 'BTC/USD',
  };

  private static readonly CATEGORY_BY_SYMBOL: Record<string, string> = {
    EURUSD: 'FOREX',
    GBPUSD: 'FOREX',
    USDJPY: 'FOREX',
    AUDUSD: 'FOREX',
    USDCAD: 'FOREX',
    XAUUSD: 'METALS',
    BTCUSD: 'CRYPTO',
  };

  private static readonly RAPIDAPI_MARKET_BY_SYMBOL: Record<string, string> = {
    EURUSD: 'CURRENCIES',
    GBPUSD: 'CURRENCIES',
    USDJPY: 'CURRENCIES',
    AUDUSD: 'CURRENCIES',
    USDCAD: 'CURRENCIES',
    XAUUSD: 'COMMODITIES',
    BTCUSD: 'CRYPTOCURRENCIES',
  };

  private static normalizeSymbol(symbol: string): string {
    return symbol?.replace(/\//g, '').replace(/\-/g, '').toUpperCase() || '';
  }

  private static toTwelveSymbol(symbol: string): string {
    return this.SYMBOL_MAP[this.normalizeSymbol(symbol)] ?? symbol.toUpperCase();
  }

  private static isValidCandle(candle: any): boolean {
    const time = Number(candle?.time);
    const open = Number(candle?.open);
    const high = Number(candle?.high);
    const low = Number(candle?.low);
    const close = Number(candle?.close);

    if (!Number.isFinite(time) || time <= 0) {
      console.warn('[MarketService] Invalid candle time', candle);
      return false;
    }

    if (![open, high, low, close].every((value) => Number.isFinite(value) && value > 0)) {
      console.warn('[MarketService] Invalid candle values', candle);
      return false;
    }

    if (high < low || high < open || high < close || low > open || low > close) {
      console.warn('[MarketService] Invalid candle range', candle);
      return false;
    }

    return true;
  }

  private static async getRapidPrice(symbol: string): Promise<number | null> {
    if (!this.RAPIDAPI_KEY) {
      return null;
    }

    const market = this.RAPIDAPI_MARKET_BY_SYMBOL[symbol] ?? 'CURRENCIES';

    try {
      const response = await axios.get(`${this.RAPID_API_BASE_URL}/v1/market/summary`, {
        params: { market, symbol },
        headers: {
          'x-rapidapi-host': 'live-stock-market.p.rapidapi.com',
          'x-rapidapi-key': this.RAPIDAPI_KEY,
          'Content-Type': 'application/json',
        },
        timeout: 10000,
      });

      const price = Number(response?.data?.data?.marketSummaryResponse?.result?.[0]?.regularMarketPrice?.raw);
      return Number.isFinite(price) && price > 0 ? price : null;
    } catch (error) {
      console.warn('[MarketService] RapidAPI summary fetch failed for', symbol, error);
      return null;
    }
  }

  static async getPrice(symbol: string) {
    const normalized = this.normalizeSymbol(symbol);
    const cacheKey = `price:${normalized}`;
    const now = Date.now();
    const cached = this.priceCache.get(cacheKey);

    if (cached && cached.expiresAt > now) {
      return cached.value;
    }

    const rapidPrice = await this.getRapidPrice(normalized);
    if (rapidPrice !== null) {
      this.priceCache.set(cacheKey, { value: rapidPrice, expiresAt: now + this.PRICE_TTL_MS });
      return rapidPrice;
    }

    const twelveSymbol = this.toTwelveSymbol(normalized);

    try {
      const response = await axios.get(`${this.BASE_URL}/price`, {
        params: { symbol: twelveSymbol, apikey: this.API_KEY },
        timeout: 10000,
      });

      const price = Number(response?.data?.price);
      const validPrice = Number.isFinite(price) && price > 0 ? price : null;
      this.priceCache.set(cacheKey, { value: validPrice, expiresAt: now + this.PRICE_TTL_MS });
      return validPrice;
    } catch (error) {
      console.error('[MarketService] Price fetch failed for', normalized, error);
      return null;
    }
  }

  static async getQuotes(symbols: string[]) {
    const results: Record<string, any> = {};

    await Promise.all(
      symbols.map(async (symbol) => {
        const normalized = this.normalizeSymbol(symbol);
        const price = await this.getPrice(normalized);

        if (price !== null) {
          results[normalized] = {
            symbol: normalized,
            price,
            bid: price,
            ask: price,
            spread: 0,
            change: 0,
            changePercent: 0,
            category: this.CATEGORY_BY_SYMBOL[normalized] ?? 'UNKNOWN',
          };
        }
      })
    );

    return results;
  }

  static async getHistoricalCandles(symbol: string) {
    const normalized = this.normalizeSymbol(symbol);
    const cacheKey = `candles:${normalized}`;
    const now = Date.now();
    const cached = this.candleCache.get(cacheKey);

    if (cached && cached.expiresAt > now) {
      return cached.value;
    }

    try {
      const yahooResponse = await axios.get(`https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(normalized)}`, {
        params: {
          interval: '1d',
          range: 'ytd',
        },
        timeout: 15000,
      });

      const chartResult = yahooResponse?.data?.chart?.result?.[0];
      const quote = chartResult?.indicators?.quote?.[0];

      let candles: any[] = [];

      if (Array.isArray(chartResult?.timestamp) && quote) {
        const timestamps = chartResult.timestamp;
        const opens = Array.isArray(quote.open) ? quote.open : [];
        const highs = Array.isArray(quote.high) ? quote.high : [];
        const lows = Array.isArray(quote.low) ? quote.low : [];
        const closes = Array.isArray(quote.close) ? quote.close : [];

        candles = timestamps
          .map((time: number, index: number) => ({
            time,
            open: Number(opens[index]),
            high: Number(highs[index]),
            low: Number(lows[index]),
            close: Number(closes[index]),
          }))
          .filter((candle: any) => this.isValidCandle(candle));
      }

      if (candles.length === 0) {
        const twelveSymbol = this.toTwelveSymbol(normalized);
        const fallbackResponse = await axios.get(`${this.BASE_URL}/time_series`, {
          params: {
            symbol: twelveSymbol,
            interval: '1min',
            outputsize: 500,
            apikey: this.API_KEY,
          },
          timeout: 15000,
        });

        const values = Array.isArray(fallbackResponse?.data?.values) ? fallbackResponse?.data?.values : [];
        candles = values
          .map((item: any) => {
            const time = Math.floor(new Date(item?.datetime ?? item?.date).getTime() / 1000);
            return {
              time,
              open: Number(item?.open),
              high: Number(item?.high),
              low: Number(item?.low),
              close: Number(item?.close),
            };
          })
          .filter((candle: any) => this.isValidCandle(candle));
      }

      this.candleCache.set(cacheKey, { value: candles, expiresAt: now + this.CANDLE_TTL_MS });
      return candles;
    } catch (error) {
      console.error('[MarketService] Historical candles fetch failed for', normalized, error);
      return [];
    }
  }
}
